// Pilot fires this after Forge completes. Body must include the client's email.
const body = $input.first().json.body || $input.first().json;
const email = (body.email || '').trim();
if (!email) throw new Error('No email provided to Pilot New Client Dashboard');
return [{ json: { email } }];

// Build the Claude prompt from the Forge onboarding row.
const row = $input.first().json;
const email = row.email;
let profile = row.client_profile;
let kickoff = row.kickoff_deck;
try { if (typeof profile === 'string') profile = JSON.parse(profile); } catch(e) {}
try { if (typeof kickoff === 'string') kickoff = JSON.parse(kickoff); } catch(e) {}
profile = profile || {};
kickoff = kickoff || {};

const prompt = `You are Pilot, the client fulfillment agent for InboundOS. A new client just finished onboarding (Forge). Build their dashboard record + week-1 task list.

CLIENT PROFILE (from Forge):
${JSON.stringify(profile, null, 2)}

KICKOFF DECK (from Forge):
${JSON.stringify(kickoff, null, 2)}

Return ONLY valid JSON, no markdown, no extra text, this exact shape:
{
  \"client\": {
    \"slug\": \"<lowercase_underscored name e.g. john_smith>\",
    \"name\": \"<full name>\",
    \"company\": \"<business name>\",
    \"niche\": \"<short niche label>\",
    \"emoji\": \"<one emoji that fits their brand>\",
    \"instagram_handle\": \"<handle without @ or empty>\",
    \"next_action\": \"<the single most important first action for Micko this week>\"
  },
  \"tasks\": [
    { \"section\": \"This Week\", \"title\": \"<task>\", \"due_date\": \"<Mon DD>\", \"category\": \"<Onboarding|Strategy|Delivery|Admin>\", \"substeps\": [\"<step>\", \"<step>\"], \"sort_order\": 1 }
  ]
}
Rules: build 4-6 week-1 tasks derived from the kickoff roadmap phase 1 + first_content_ideas. Keep titles short and actionable. Substeps 2-3 each.`;

return [{ json: { prompt, email } }];

const raw = $input.first().json.output || $input.first().json.stdout || '';
const email = $('Build Prompt').first().json.email;
let parsed;
try {
  const clean = raw.replace(/```json?/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('Claude did not return valid JSON: ' + raw.slice(0, 200));
}
const client = parsed.client || {};
const tasks = parsed.tasks || [];
return [{ json: { email, client, tasks } }];

// Build client_tasks rows now that we have the new client id.
const inserted = $input.first().json;
const clientRow = Array.isArray(inserted) ? inserted[0] : inserted;
const clientId = clientRow.id;
const tasks = $('Parse Claude Output').first().json.tasks || [];
const rows = tasks.map((t, i) => ({
  client_id: clientId,
  section: t.section || 'This Week',
  title: t.title,
  due_date: t.due_date || '',
  category: t.category || 'Delivery',
  tags: t.tags || [],
  substeps: t.substeps || [],
  done: false,
  sort_order: t.sort_order || (i + 1)
}));
return [{ json: { rows, clientId, email: $('Parse Claude Output').first().json.email } }];
